   331→fn run_push_workflow(args: &PushArgs) -> Result<(), String> {
   332→    use std::process::Command;
   333→
   334→    let branch = match &args.branch {
   335→        Some(b) => b.clone(),
   336→        None => {
   337→            let output = Command::new("git")
   338→                .args(["rev-parse", "--abbrev-ref", "HEAD"])
   339→                .output()
   340→                .map_err(|e| format!("Failed to get current branch: {}", e))?;
   341→
   342→            if !output.status.success() {
   343→                return Err("Failed to determine current branch".to_string());
   344→            }
   345→
   346→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   347→        }
   348→    };
   349→
   350→    eprintln!("push: pushing {} to {}", branch, args.remote);
   351→
   352→    let mut push_args = vec!["push", &args.remote, &branch];
   353→    if args.force {
   354→        push_args.push("--force");
   355→    }
   356→
   357→    let output = Command::new("git")
   358→        .args(&push_args)
   359→        .output()
   360→        .map_err(|e| format!("Failed to run git push: {}", e))?;
   361→
   362→    if !output.status.success() {
   363→        let stderr = String::from_utf8_lossy(&output.stderr);
   364→        return Err(format!("git push failed: {}", stderr));
   365→    }
   366→
   367→    Ok(())
   368→}
